/**
 * @fileoverview Sidebar constants.
 * @module module/Sidebar/constants
 */

import { defineParts } from '../shared/definePart.js';
import { TRANSITION_COLORS, SCROLL_BODY } from '../shared/styleFragments.js';

export const CLS = Object.freeze({
    ROOT:    'sidebar',
    HEADER:  'sidebar-header',
    BODY:    'sidebar-body',
    FOOTER:  'sidebar-footer',
    SECTION: 'sidebar-section',
    HEADING: 'sidebar-heading',
    ITEM:    'sidebar-item',
    LABEL:   'sidebar-label',
    DIVIDER: 'sidebar-divider',
    SPACER:  'sidebar-spacer',
    CURRENT: 'is-current',
});

export const DEFAULTS = Object.freeze({});

export const PART = defineParts('Sidebar', {
    ROOT:    { class: 'sidebar-root', aliases: ['root', 'sidebar'] },
    HEADER:  { class: 'sidebar-header', aliases: ['header'] },
    BODY:    { class: 'sidebar-body', aliases: ['body'] },
    FOOTER:  { class: 'sidebar-footer', aliases: ['footer'] },
    SECTION: { class: 'sidebar-section', aliases: ['section'] },
    HEADING: { class: 'sidebar-heading', aliases: ['heading'] },
    ITEM:    { class: 'sidebar-item', aliases: ['item', 'link'] },
    LABEL:   { class: 'sidebar-label', aliases: ['label'] },
    DIVIDER: { class: 'sidebar-divider', aliases: ['divider'] },
    SPACER:  { class: 'sidebar-spacer', aliases: ['spacer'] },
});

PART.ROOT.jit    = 'flex flex-col h-full bg-[var(--sb-bg)] [font-family:var(--sb-font-stack)]';
PART.HEADER.jit  = 'shrink-0 px-[var(--sb-px)] py-[var(--sb-header-py)]';
PART.BODY.jit    = `${SCROLL_BODY} px-[var(--sb-px)] py-[var(--sb-body-py)]`;
PART.FOOTER.jit  = 'shrink-0 px-[var(--sb-px)] py-[var(--sb-footer-py)] [border-top:1px_solid_var(--sb-border)]';
PART.SECTION.jit = 'flex flex-col gap-[var(--sb-section-gap)]';
PART.HEADING.jit = 'text-[var(--sb-heading-size)] font-semibold fg-[var(--sb-heading-text)] px-[var(--sb-item-px)] py-[var(--sb-heading-py)]';
PART.ITEM.jit    = `flex items-center gap-[var(--sb-item-gap)] px-[var(--sb-item-px)] py-[var(--sb-item-py)] text-[var(--sb-item-font-size)] fg-[var(--sb-item-text)] rounded-[var(--sb-item-radius)] cursor-pointer ${TRANSITION_COLORS} hover:bg-[var(--sb-item-hover-bg)] {is-current}:bg-[var(--sb-item-active-bg)] {is-current}:fg-[var(--sb-item-active-text)] [text-decoration:none]`;
PART.LABEL.jit   = 'truncate';
PART.DIVIDER.jit = 'h-[1px] bg-[var(--sb-border)] my-[var(--sb-divider-my)]';
PART.SPACER.jit  = 'flex-1';
