/**
 * @fileoverview Sidebar barrel.
 * @module module/Sidebar
 */
import { default as razyui } from '../index.js';
import { SidebarDef as DEF } from './Sidebar.def.js';
import Sidebar from './Sidebar/index.js';

razyui.Sidebar = Sidebar;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Sidebar);
}

export default Sidebar;

export const stylesheet = null;
